package main

import (
	"html/template"
	"net/http"
)

type Comment struct {
	Author string
	Text   string
}

var comments = []Comment{
	{Author: "Alice", Text: "<strong>This</strong> is a comment."},
	{Author: "Bob", Text: "Here's another comment with <em>italic</em> text."},
}

func commentsHandler(w http.ResponseWriter, r *http.Request) {
	tmpl := `
<!DOCTYPE html>
<html>
<head>
    <title>User Comments</title>
</head>
<body>
    <h1>User Comments</h1>
    <ul>
        {{range .}}
        <li><strong>{{.Author}}:</strong> {{.Text}}</li>
        {{end}}
    </ul>
</body>
</html>
`
	t, err := template.New("comments").Parse(tmpl)
	if err != nil {
		http.Error(w, err.Error(), http.StatusInternalServerError)
		return
	}
	if err := t.Execute(w, comments); err != nil {
		http.Error(w, err.Error(), http.StatusInternalServerError)
	}
}

func main() {
	http.HandleFunc("/comments", commentsHandler)
	http.ListenAndServe(":8080", nil)
}